import { PurchaseOrder as PurchaseOrderComponent } from '@/checkout/components';
import { validateNotEmpty } from '@/checkout/lib/validation';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Container } from '@adobe-commerce/elsie/lib';
import { HTMLAttributes, useCallback, useState } from 'preact/compat';

export interface PurchaseOrderProps extends HTMLAttributes<HTMLFormElement> {
  initialReferenceNumber?: string;
  onReferenceNumberChange?: (referenceNumber: string) => void;
  onReferenceNumberBlur?: (referenceNumber: string) => void;
}

export const PurchaseOrder: Container<PurchaseOrderProps> = ({
  initialReferenceNumber = '',
  onReferenceNumberChange,
  onReferenceNumberBlur,
  ...props
}) => {
  const [error, setError] = useState<string>('');
  const [referenceNumber, setReferenceNumber] = useState<string>(
    initialReferenceNumber
  );

  const { missingRefNumberError } = useText({
    missingRefNumberError: 'Checkout.PurchaseOrder.missingReferenceNumberError',
  });

  const validateRefNumber = useCallback(
    (value: string) => {
      const isMissing = validateNotEmpty(value);
      setError(isMissing ? '' : missingRefNumberError);
    },
    [missingRefNumberError]
  );

  const checkValidity = useCallback(
    (validity: ValidityState) => {
      setError(validity.valid ? '' : missingRefNumberError);
    },
    [missingRefNumberError]
  );

  const handleReferenceNumberChange = useCallback(
    (event: Event) => {
      const target = event.target as HTMLInputElement;
      const value = target.value;
      setReferenceNumber(value);
      validateRefNumber(value);
      onReferenceNumberChange?.(value);
    },
    [onReferenceNumberChange, validateRefNumber]
  );

  const handleReferenceNumberBlur = useCallback(
    (event: Event) => {
      const target = event.target as HTMLInputElement;
      const value = target.value;
      validateRefNumber(value);
      onReferenceNumberBlur?.(value);
    },
    [onReferenceNumberBlur, validateRefNumber]
  );

  const handleInvalidReferenceNumber = useCallback(
    (event: Event) => {
      const target = event.target as HTMLInputElement;
      checkValidity(target.validity);
    },
    [checkValidity]
  );

  return (
    <PurchaseOrderComponent
      {...props}
      error={error}
      referenceNumber={referenceNumber}
      onInvalidReferenceNumber={handleInvalidReferenceNumber}
      onReferenceNumberBlur={handleReferenceNumberBlur}
      onReferenceNumberChange={handleReferenceNumberChange}
    />
  );
};
